export const ARTIST_TIERS = Array.from(new Set(ARTISTS.map(a => a.tier).filter(Boolean))).sort();
export const ARTIST_GENRES = Array.from(new Set(ARTISTS.flatMap(a => a.genres))).sort();
export const ARTIST_CITIES = Array.from(new Set(ARTISTS.map(a => {
  const b = (a.based || a.from).split(/[,/|]/)[0].trim();
  return b || "Other";
}))).sort();
